use distributed_inference::mesh_probability_admission::{
    MeshProbabilityAdmission, MeshProbabilityDecision, MeshProbabilityPolicy,
};

#[test]
fn hot_mesh_key_admits_cached_payload_after_finite_observations() {
    let mut admission = MeshProbabilityAdmission::new(MeshProbabilityPolicy {
        min_observations: 3,
        min_concentration_bps: 7_000,
        residual_budget: 1,
        max_entries: 16,
    });

    let first = admission.observe("/.aeon/fib20-rf?n=20&format=bwf2");
    admission.remember(&first.key, b"bwf2-payload".to_vec());
    admission.observe("/.aeon/runtime-attestation");
    admission.observe("/.aeon/fib20-rf?n=20&format=bwf2");
    admission.observe("/.aeon/fib20-rf?n=20&format=bwf2");
    let witness = admission.observe("/.aeon/fib20-rf?n=20&format=bwf2");

    assert!(matches!(
        witness.decision,
        MeshProbabilityDecision::Reuse | MeshProbabilityDecision::Speculate
    ));
    assert_eq!(
        admission.get_admitted_cached(&witness),
        Some(b"bwf2-payload".to_vec())
    );
}

#[test]
fn uncovered_mesh_residual_does_not_admit_cached_payload() {
    let mut admission = MeshProbabilityAdmission::new(MeshProbabilityPolicy {
        min_observations: 3,
        min_concentration_bps: 9_000,
        residual_budget: 1,
        max_entries: 16,
    });

    let first = admission.observe("hot");
    admission.remember(&first.key, b"payload".to_vec());
    admission.observe("cold-a");
    admission.observe("cold-b");
    admission.observe("hot");
    let witness = admission.observe("hot");

    assert_eq!(witness.decision, MeshProbabilityDecision::Cover);
    assert_eq!(admission.get_admitted_cached(&witness), None);
}
